custom_css:
.letter-head {
	border-radius: 18px;
	padding-right: 12px;
	margin-left: 12px;
	margin-right: 12px;
}

.letter-head td {
	padding: 0px !important;
}
.invoice-header {
	width: 100%;
}
.logo-cell {
	width: 100px;
	text-align: center;
	position: relative;
}
.logo-container {
	width: 90px;
	display: block;
}
.logo-container img {
	max-width: 90px;
	max-height: 90px;
	display: inline-block;
	border-radius: 15px;
}
.company-details {
	width: 40%;
	align-content: center;
}
.company-name {
	font-size: 14px;
	font-weight: bold;
	color: #171717;
	margin-bottom: 4px;
}
.invoice-info-cell {
	float: right;
	vertical-align: top;
}
.invoice-info {
	margin-bottom: 2px;
}
.invoice-label {
	color: #7c7c7c;
	display: inline-block;
	margin-right: 5px;
}
